mapper.sql:
SELECT A.APY_SEQ , A.APY_NM , A.BTHDAY , A.SBSC_PRDT_CD , DECODE(A.SBSC_PRDT_CD, '01', '모바일', '') AS SBSC_PRDT_NM , REPLACE(A.CNTC_TEL_NO, '-', '') AS CNTC_TEL_NO , REPLACE(A.TGT_SVC_NO, '-', '') AS TGT_SVC_NO , A.RECP_EMAIL , A.CONF_SBST01_YN , A.CONF_SBST02_YN , A.CONF_SBST03_YN , A.CONF_SBST04_YN , TO_CHAR(A.APY_DT, 'YYYYMMDD') AS APY_DT , DECODE(A.RESULT_YN, 'Y', '처리', '미처리') AS RESULT_YN , TO_CHAR(A.PROC_DT, 'YYYYMMDD') AS PROC_DT , FN_GET_USRNM(A.PROCR_ID) AS PROCR_NM , CASE WHEN 'REQ' = #{searchCd} THEN DECODE((SELECT COUNT(*) FROM MSP_INVST_REQ_MST B, MSP_JUO_CUS_INFO C WHERE REPLACE(A.TGT_SVC_NO, '-', '') = B.SUBSCRIBER_NO AND A.MYSLF_ATHN_CI = C.SELF_CSTMR_CI AND B.CUSTOMER_ID = C.CUSTOMER_ID AND REQ_TYPE = '10'
), 0, 'N', 'Y') WHEN 'PRV' = #{searchCd} THEN DECODE((SELECT COUNT(*) FROM MSP_INVST_REQ_MST B, MSP_JUO_CUS_INFO C WHERE REPLACE(A.TGT_SVC_NO, '-', '') = SUBSCRIBER_NO AND A.MYSLF_ATHN_CI = C.SELF_CSTMR_CI AND B.CUSTOMER_ID = C.CUSTOMER_ID AND REQ_TYPE = '10'
), 0, 'N', 'Y') ELSE 'N' END AS IS_INVST_PROC FROM MSP_COMM_DAT_PRV_TXN A WHERE TO_CHAR(A.APY_DT, 'YYYYMMDD') BETWEEN #{strtDt} AND #{endDt}
AND A.APY_NM LIKE '%' || #{searchVal} || '%'
AND REPLACE(A.CNTC_TEL_NO, '-', '') = #{searchVal}
AND NVL(A.RESULT_YN, 'N') = #{resultYn}

mapper.select:
SELECT APY_SEQ , APY_NM , BTHDAY , SBSC_PRDT_CD , SBSC_PRDT_NM , CNTC_TEL_NO , TGT_SVC_NO , RECP_EMAIL , CONF_SBST01_YN , CONF_SBST02_YN , CONF_SBST03_YN , CONF_SBST04_YN , APY_DT , RESULT_YN , PROC_DT , PROCR_NM , DECODE(IS_INVST_PROC, 'Y', '제공', '미제공') AS IS_INVST_PROC_NM , IS_INVST_PROC FROM(
) WHERE 1=1
AND IS_INVST_PROC = #{isInvstProc}
ORDER BY APY_DT DESC

SELECT APY_SEQ , APY_NM , BTHDAY , SBSC_PRDT_CD , SBSC_PRDT_NM , CNTC_TEL_NO , TGT_SVC_NO , RECP_EMAIL , CONF_SBST01_YN , CONF_SBST02_YN , CONF_SBST03_YN , CONF_SBST04_YN , APY_DT , RESULT_YN , PROC_DT , PROCR_NM , DECODE(IS_INVST_PROC, 'Y', '제공', '미제공') AS IS_INVST_PROC_NM FROM(
) WHERE 1=1
AND IS_INVST_PROC = #{isInvstProc}
ORDER BY APY_DT DESC

mapper.update:
UPDATE 
	MSP_COMM_DAT_PRV_TXN
SET 
	 RESULT_YN = #{resultYn}
	, PROCR_ID = #{sessionUserId}
	, PROC_DT = SYSDATE
WHERE 
	APY_SEQ = #{apySeq}
